lxslt:component.lxslt:script:
function repeat(n,c){
	return Array(n).join(c);
}
function getGIPNarration(str){
	var c, sender = '', desc = '', narration = '';

	if(str.indexOf('P01') != -1){
		c = Number.parseInt(str.indexOf('P01'))+3;
		sender = str.substr((c+3),str.substr(c,3));
	}

	if(str.indexOf('P03') != -1){
		c = Number.parseInt(str.indexOf('P03'))+3;
		desc = str.substr((c+3),str.substr(c,3));
	}
	if(sender != '') narration+=sender;
	if(desc != '') narration+=' ' + desc;

	//narration = narration.replace(/"|\*|;|~|`|\||!|@|%|&|\\|<|>/gi,' ');
	narration = narration.replace(/"|\,|\*|;|~|`|\||!|@|%|&|\\|<|>/gi,' ');
	return narration;
}

function replaceStrangeChars(str){
	return str.replace(/"|\*|;|~|`|\||!|@|%|&|\\|<|>/gi,' ');
}

function multiConcat(ctx, delim){
    var ipString = "";
    if (ctx.length){
	for (var i=0; i < ctx.getLength(); i++){
  	    ctxN  = ctx.item(i);
	    if (ctxN.nodeType == 1){
	        ipString +=  _wander(ctxN, delim);
	    }
	    if (ctxN.nodeType == 2){
	        ipString += ctxN.nodeValue;
   	    }
	}
    }else{
	return '';
    }
    return ipString.length>1 ? ipString.substring(delim.length) : ipString;
}
function   _wander(ctx, delim){
	var retStr = "";
	var nodelist = ctx.childNodes;

	for (var i=0; i < ctx.childNodes.length; i++){

		ctxN = nodelist.item(i);//ctx.childNodes[i];

		switch(ctxN.nodeType){
			case 1:
				retStr +=   _wander(ctxN);
				break;
			case 3:
				retStr += delim +ctxN.nodeValue;
				break;
			default:
				break;
		}
	}
	return retStr;
}

function FTID(str)
{
  var n = str.lastIndexOf("FT");
return str.substring(n,n+12);

}



function compute(expr){
	return eval(expr);
}

function nextMillenium(){
	d = new Date()    //today's date
	mill=new Date(3000, 00, 01, 00, 00, 00)    //Next millennium start date
	diff = mill-d    //difference in milliseconds
	mtg = new String(diff/86400000)    //calculate days and convert to string
	point=mtg.indexOf(".")    //find the decimal point
	days=mtg.substring(0,point)    //get just the whole days
	return "There are only " + days + " days remaining to the start of the next millennium."; 
}

function replace(input, pattern, flags, str){
	return input.replace(new RegExp(pattern, flags), str);
}

function trimBOM(str){
 var n = str.indexOf("?xml");
  var x = str.substr(n-1);
	return   x;
}


function zerofill(number, length) {
    var result = number.toString();
    var pad = length - result.length;

    while(pad > 0) {
        result = '0' + result;
        pad--;
    }

    return result;
}

function getNthSubstrPos(str, sub, n) {
    if (n > str.split(sub).length - 1) return -1;
    var recursePosition = function(n) {
        if (n === 0) return str.indexOf(sub);
        return str.indexOf(sub, recursePosition(n - 1) + 1);
    };
    return recursePosition(n);
};

function XformEnquiryResults(inq){
	var ds = getNthSubstrPos(inq,',',1);
	var t = (inq.substr(ds+1).replace(/,[a-zA-Z0-9\.\:]+?\=/gi,'"'+"\t"+'"')+'"').replace(/[a-zA-Z0-9\.\:]+?\=/gi,'"');
	return inq.substring(0,ds+1)+t;

	//return inq;
};

