function replaceControlCharacters(inputString) {

    return inputString.replace(/[\x00-\x1F\x7F]/g, '');
}



function getLastIndexOfDoubleUnderscore(str) {
    return str.lastIndexOf("__")+3;
}


function appendETX(str) {
  return str + String.fromCharCode(3);
}


function split35chars(s){
 return s.split(/\/\/+/).map(x => x).filter(Boolean)[0];
}


function Line1(s){
 return s.split(/\/\/+/).map(x => x).filter(Boolean)[0];

}

function Line2(s){
 return s.split(/\/\/+/).map(x => x).filter(Boolean)[1];
}

function Line3(s){
 return s.split(/\/\/+/).map(x => x).filter(Boolean)[2];
}



function read35Chars(input, start, end){
 return input.substring(start, end);
}



// Returns a Date that is 5 seconds before "now"
function fiveSecondsAgo() {
  return new Date(Date.now() - 5000).toISOString();;
}
